using System.ComponentModel;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;
using OpenAI;

var builder = Host.CreateApplicationBuilder(args);

builder.Services.AddChatClient(b => b
    .UseLogging()
    .UseOpenAIChatClient(
        builder.Configuration["AI:ModelId"] ?? "gpt-4o-mini-2024-07-18"));

builder.Services.AddSingleton<ResearchNotes>();

using var host = builder.Build();

var chatClient = host.Services.GetRequiredService<IChatClient>();
var notes = host.Services.GetRequiredService<ResearchNotes>();
var loggerFactory = host.Services.GetRequiredService<ILoggerFactory>();

var tools = new AITool[]
{
    AIFunctionFactory.Create(
        (string query) => WebSearchTool.SearchAsync(query),
        "web_search",
        "Searches the web for the given query and returns a list of results with titles, URLs, and snippets."),

    AIFunctionFactory.Create(
        ([Description("The key or title for the note")] string key,
         [Description("The content to save")] string content) =>
        {
            notes.Add(key, content);
            return $"Note saved under '{key}'.";
        },
        "save_note",
        "Saves a research note with a key and content for later reference."),

    AIFunctionFactory.Create(
        () => notes.GetAll(),
        "get_notes",
        "Retrieves all saved research notes as a formatted string."),
};

var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. When given a topic, you:
        1. Search the web for relevant information using the web_search tool (perform 2-3 searches with different queries).
        2. Save important findings using the save_note tool, organizing by subtopic.
        3. After gathering enough information, retrieve your notes with get_notes and produce a well-structured summary.

        Always cite your sources. Be thorough but concise.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and summarizing findings.",
    tools: tools,
    loggerFactory: loggerFactory);

Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       🔍 Research Agent              ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();
Console.Write("Enter a research topic (or 'quit' to exit): ");

while (Console.ReadLine() is { } input && !input.Equals("quit", StringComparison.OrdinalIgnoreCase))
{
    if (string.IsNullOrWhiteSpace(input))
    {
        Console.Write("\nEnter a research topic (or 'quit' to exit): ");
        continue;
    }

    notes.Clear();
    Console.WriteLine($"\nResearching: {input}\n");

    try
    {
        var response = await agent.RunAsync(
            input,
            options: new ChatClientAgentRunOptions(new ChatOptions
            {
                Temperature = 0f,
                MaxOutputTokens = 2048,
            }));

        Console.WriteLine("── Summary ──────────────────────────────");
        Console.WriteLine(response.Text);
        Console.WriteLine("──────────────────────────────────────────");

        if (response.Usage is { } usage)
        {
            Console.WriteLine($"[Tokens — input: {usage.InputTokenCount}, output: {usage.OutputTokenCount}]");
        }
    }
    catch (Exception ex)
    {
        Console.WriteLine($"Error: {ex.Message}");
    }

    Console.Write("\nEnter a research topic (or 'quit' to exit): ");
}

Console.WriteLine("Goodbye!");

// --- Supporting types ---

/// <summary>Simulated web search tool that returns plausible results for any query.</summary>
static class WebSearchTool
{
    public static Task<string> SearchAsync(string query)
    {
        // In production, replace with a real search API (Bing Search, Google Custom Search, etc.)
        var results = new[]
        {
            new
            {
                Title = $"{query} - Overview and Key Facts",
                Url = $"https://en.wikipedia.org/wiki/{Uri.EscapeDataString(query.Replace(' ', '_'))}",
                Snippet = $"Comprehensive overview of {query}, covering history, current developments, and key facts."
            },
            new
            {
                Title = $"Latest Research on {query}",
                Url = $"https://scholar.example.com/search?q={Uri.EscapeDataString(query)}",
                Snippet = $"Recent academic papers and research findings related to {query}."
            },
            new
            {
                Title = $"{query}: News and Developments",
                Url = $"https://news.example.com/topic/{Uri.EscapeDataString(query)}",
                Snippet = $"Breaking news and recent developments about {query} from leading publications."
            },
        };

        return Task.FromResult(JsonSerializer.Serialize(results, new JsonSerializerOptions { WriteIndented = true }));
    }
}

/// <summary>Thread-safe note storage for the research agent.</summary>
sealed class ResearchNotes
{
    private readonly Dictionary<string, string> _notes = [];

    public void Add(string key, string content)
    {
        lock (_notes)
        {
            _notes[key] = content;
        }
    }

    public string GetAll()
    {
        lock (_notes)
        {
            if (_notes.Count == 0)
                return "No notes saved yet.";

            return string.Join("\n\n", _notes.Select(kv => $"## {kv.Key}\n{kv.Value}"));
        }
    }

    public void Clear()
    {
        lock (_notes)
        {
            _notes.Clear();
        }
    }
}

